--- 保卫战, 英雄对象

---@class LDefenceWarHero
local LDefenceWarHero  = LxClass("LDefenceWarHero", nil)

local LDefenceWarSkill = LXImport("..Object.LDefenceWarSkill")

local Vector3          = Vector3

function LDefenceWarHero:LDefenceWarHero(ctrl)
    self._ctrl = ctrl
end

-- 销毁
function LDefenceWarHero:Destroy()
    for k, obj in ipairs(self._skillObjList) do
        obj:Destroy()
    end
    self._skillObjList = {}

    table.removeall(self)
end

-- 初始化
function LDefenceWarHero:Init(heroId)
    self._heroId = heroId
    self._heroLev = gModelDefenceWar:GetHeroLev(heroId)
    self._heroLevRef = gModelDefenceWar:GetHeroLevRef(heroId, self._heroLev)

    -- 列表的第一个技能为本体技能
    self._skillObjList = {}

    -- bufff
    self._buffList = {}

    -- 总伤害
    self._totalHurt = 0
end

-- 获取控制器
function LDefenceWarHero:GetCtrl()
    return self._ctrl
end

-- 获取英雄id
function LDefenceWarHero:GetHeroId()
    return self._heroId
end

-- 获取英雄等级配置
function LDefenceWarHero:GetHeroLevRef()
    return self._heroLevRef
end

-- UpDate
function LDefenceWarHero:Update(dt, monsterInSkillRange)
    for k, obj in ipairs(self._skillObjList) do
        if obj:Update(dt, monsterInSkillRange) then
            return true
        end
    end
    return false
end

-- 获取技能对象列表
function LDefenceWarHero:GetSkillObjList()
    return self._skillObjList
end

-- 添加或更新技能对象
function LDefenceWarHero:AddOrUpdateSkill(skillId, skillLev)
    for k, obj in ipairs(self._skillObjList) do
        if obj:GetSkillId() == skillId then
            obj:SetSkillLev(skillLev)
            -- todo: 发送消息，技能更新ui
            return
        end
    end

    if #self._skillObjList >= 4  then
        if LOG_INFO_ENABLED then
            gModelDefenceWar:Log("每个英雄最多只能拥有4个技能")
        end
        return
    end

    local obj = LDefenceWarSkill:New(self)
    obj:Init(skillId, skillLev)
    table.insert(self._skillObjList, obj)
end

-- 获取技能对象
function LDefenceWarHero:GetSkillObj(skillId)
    for k, obj in ipairs(self._skillObjList) do
        if obj:GetSkillId() == skillId then
            return obj
        end
    end
    return nil
end

-- 添加buff
function LDefenceWarHero:AddBuff(heroId, skillId, skillLev, attrName, attrType, attrVal)
    for _, v in ipairs(self._buffList) do
        if v.heroId == heroId and v.skillId == skillId then
            v.attrVal = attrVal
            return
        end
    end

    local skillObj = self._ctrl:GetSkillObj(heroId, skillId)
    local duration = skillObj:GetDuration()

    local buff = {
        heroId   = heroId,
        skillId  = skillId,
        skillLev = skillLev,
        duration = duration,
        endTime  = duration,
        attrName = attrName,
        attrType = attrType,
        attrVal  = attrVal,
    }
    table.insert(self._buffList, buff)
end

-- 移除buff
function LDefenceWarHero:RemoveBuff(heroId, skillId)
    for k, v in ipairs(self._buffList) do
        if v.heroId == heroId and v.skillId == skillId then
            table.remove(self._buffList, k)
            return
        end
    end
end

-- 获取buff列表
function LDefenceWarHero:GetBuffList()
    return self._buffList
end

-- 获取攻击
function LDefenceWarHero:GetAtk()
    local baseAtk = self._heroLevRef.atk
    local buffAtk = 0
    local attrName = "atk"
    for _, tab in ipairs(self._buffList) do
        if tab.attrName == attrName then
            if tab.attrType == 1 then
                -- 百分比
                buffAtk = buffAtk + baseAtk * tab.attrVal * 0.01
            else
                buffAtk = buffAtk + tab.attrVal
            end
        end
    end
    return baseAtk + buffAtk
end

-- 添加伤害
function LDefenceWarHero:AddHurt(hurt)
    self._totalHurt = self._totalHurt + hurt
end

-- 获取总伤害
function LDefenceWarHero:GetTotalHurt()
    return self._totalHurt
end

-- 暂停
function LDefenceWarHero:OnPauseGame()
    for k, v in ipairs(self._skillObjList) do
        v:OnPauseGame()
    end
end

-- 恢复
function LDefenceWarHero:OnResumeGame()
    for k, v in ipairs(self._skillObjList) do
        v:OnResumeGame()
    end
end

return LDefenceWarHero
